/**
 * Provides Moodle modal confirmations for delete actions within tag management.
 *
 * @module format_minimoodlewall/delete_confirm
 */
define([
    'core/modal_delete_cancel',
    'core/modal_events',
    'core/notification',
], function(ModalDeleteCancel, ModalEvents, Notification) {
    const SELECTOR = '[data-minimoodlewall-confirm]';

    /**
     * Register click handler for a delete link.
     *
     * @param {HTMLAnchorElement} link
     */
    const registerHandler = (link) => {
        if (link.dataset.minimoodlewallConfirmInitialised) {
            return;
        }
        link.dataset.minimoodlewallConfirmInitialised = '1';

        link.addEventListener('click', (event) => {
            event.preventDefault();

            const targetUrl = link.getAttribute('href');
            if (!targetUrl) {
                return;
            }

            ModalDeleteCancel.create({
                title: link.dataset.confirmTitle || '',
                body: link.dataset.confirmMessage || '',
                show: true,
            }).then((modal) => {
                if (link.dataset.confirmYes) {
                    modal.setDeleteButtonText(link.dataset.confirmYes);
                }
                if (link.dataset.confirmNo) {
                    modal.setButtonText('cancel', link.dataset.confirmNo);
                }

                const root = modal.getRoot();

                root.on(ModalEvents.delete, () => {
                    modal.hide();
                    window.location.href = targetUrl;
                });

                root.on(ModalEvents.cancel, () => modal.hide());
                root.on(ModalEvents.hidden, () => modal.destroy());
                return null;
            }).catch(Notification.exception);
        });
    };

    /**
     * Initialise confirmation handlers.
     */
    const init = () => {
        document.querySelectorAll(SELECTOR).forEach(registerHandler);
    };

    return {init};
});
